const body = $input.first().json.body || $input.first().json;
const token = body.token || body.symbol || body.pair;
const chain = body.chain || 'ethereum';
const question = body.question || `Should I invest in ${token}?`;

if (!token) throw new Error('Missing token/symbol/pair in request body');

return [{ json: { token, chain, question } }];

const market = $('Fetch Market Data').first().json;
const ta = $('Fetch TA').first().json;
const security = $('Fetch Security').first().json;
const ml = $('ML Prediction').first().json;
const params = $('Parse Request').first().json;

const price = market.prices?.[0] || {};

const dataContext = {
  token: params.token,
  chain: params.chain,
  question: params.question,
  currentPrice: price.price || 0,
  change24h: price.change24h || 0,
  volume24h: price.volume24h || 0,
  marketCap: price.marketCap || 0,
  ta: {
    rsi: ta.rsi || 'N/A',
    macd: ta.macd || 'N/A',
    sma20: ta.sma20 || 'N/A',
    sma50: ta.sma50 || 'N/A',
    ema12: ta.ema12 || 'N/A',
    bollingerBands: ta.bollingerBands || 'N/A',
    support: ta.support || 'N/A',
    resistance: ta.resistance || 'N/A',
    trend: ta.trend || 'N/A'
  },
  security: {
    riskScore: security.riskScore || security.risk_score || 'N/A',
    contractVerified: security.contractVerified || false,
    hasProxy: security.hasProxy || false,
    ownershipRenounced: security.ownershipRenounced || false,
    flags: security.flags || security.warnings || []
  },
  ml: {
    direction: ml.direction || 'N/A',
    confidence: ml.confidence || 0,
    predictedChange: ml.predictedChange || ml.predicted_change || 0,
    modelVersion: ml.modelVersion || ml.model_version || 'N/A'
  }
};

const step1Prompt = `You are Vizzor, an expert crypto analyst AI. You must analyze the following data for ${params.token} and produce a structured analysis. Do NOT make recommendations yet - only analyze.\n\n` +
  `USER QUESTION: ${params.question}\n\n` +
  `DATA:\n${JSON.stringify(dataContext, null, 2)}\n\n` +
  `Produce a structured analysis with these sections:\n` +
  `1. PRICE ACTION ANALYSIS: Current price context, momentum, key levels\n` +
  `2. TECHNICAL ANALYSIS: Interpret the indicators (RSI, MACD, moving averages, Bollinger Bands)\n` +
  `3. SECURITY ASSESSMENT: Contract risks, red flags, trust factors\n` +
  `4. ML MODEL SIGNAL: Interpret the ML prediction in context\n` +
  `5. KEY OBSERVATIONS: 3-5 bullet points of the most important findings\n\n` +
  `Be precise, data-driven, and honest about uncertainties.`;

return [{ json: { step1Prompt, dataContext } }];

const analysis = $('Structure Step 2 Prompt').first().json.analysis;
const recommendation = $input.first().json.message?.content || $input.first().json.text || $input.first().json.choices?.[0]?.message?.content || '';
const dataContext = $('Structure Step 1 Prompt').first().json.dataContext;

const fullReport = {
  token: dataContext.token,
  chain: dataContext.chain,
  question: dataContext.question,
  analysis,
  recommendation,
  data: {
    price: dataContext.currentPrice,
    change24h: dataContext.change24h,
    mlDirection: dataContext.ml.direction,
    mlConfidence: dataContext.ml.confidence,
    securityRisk: dataContext.security.riskScore
  },
  generatedAt: new Date().toISOString()
};

return [{ json: fullReport }];
